import{_ as t,o as r,c as s,ai as a}from"./chunks/framework.Bke2s2V8.js";const m=JSON.parse('{"title":"Les verbes irréguliers","description":"","frontmatter":{},"headers":[],"relativePath":"module-2-construire-une-phrase/verbes-irreguliers.md","filePath":"module-2-construire-une-phrase/verbes-irreguliers.md","lastUpdated":1773303592000}'),d={name:"module-2-construire-une-phrase/verbes-irreguliers.md"};function i(l,e,n,o,c,b){return r(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="les-verbes-irreguliers" tabindex="-1">Les verbes irréguliers <a class="header-anchor" href="#les-verbes-irreguliers" aria-label="Permalink to “Les verbes irréguliers”">​</a></h1><p><strong>Prérequis :</strong> <a href="./present-verbes-reguliers.html">Le présent - verbes réguliers</a></p><p><strong>Objectif :</strong> connaître la conjugaison de sein, haben et werden, les trois verbes les plus utilisés de la langue.</p><p>Ces trois verbes sont irréguliers et ne suivent pas les règles des verbes faibles. Ils sont indispensables, on les retrouve dans presque toutes les phrases.</p><h2 id="sein-etre" tabindex="-1">sein - être <a class="header-anchor" href="#sein-etre" aria-label="Permalink to “sein - être”">​</a></h2><p><em>Sein</em> est le verbe le plus irrégulier de l&#39;allemand. Sa conjugaison est a apprendre par coeur.</p><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Pronom</th><th class="p-3 text-center font-semibold text-green-700">Forme</th><th class="p-3 text-left font-semibold text-gray-600">Exemple</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium">ich</td><td class="p-3 text-center font-bold text-green-700">bin</td><td class="p-3 text-gray-500 italic">Ich bin Franzose. - Je suis français.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">du</td><td class="p-3 text-center font-bold text-green-700">bist</td><td class="p-3 text-gray-500 italic">Du bist mude. - Tu es fatigue.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-medium">er/sie/es</td><td class="p-3 text-center font-bold text-green-700">ist</td><td class="p-3 text-gray-500 italic">Es ist kalt. - Il fait froid.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">wir</td><td class="p-3 text-center font-bold text-green-700">sind</td><td class="p-3 text-gray-500 italic">Wir sind zu Hause. - Nous sommes a la maison.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-medium">ihr</td><td class="p-3 text-center font-bold text-green-700">seid</td><td class="p-3 text-gray-500 italic">Ihr seid spat. - Vous etes en retard.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">sie/Sie</td><td class="p-3 text-center font-bold text-green-700">sind</td><td class="p-3 text-gray-500 italic">Sie sind nett. - Ils sont sympas.</td></tr></tbody></table></div><div class="warning custom-block"><p class="custom-block-title">Sein est totalement irrégulier</p><p>Contrairement aux verbes réguliers, <em>sein</em> n&#39;a aucun rapport entre l&#39;infinitif et ses formes conjuguees. C&#39;est le seul verbe allemand aussi irrégulier, il faut l&#39;apprendre integralement par coeur.</p></div><h2 id="haben-avoir" tabindex="-1">haben - avoir <a class="header-anchor" href="#haben-avoir" aria-label="Permalink to “haben - avoir”">​</a></h2><p><em>Haben</em> est presque régulier, a une exception pres : les formes <em>du hast</em> et <em>er/sie/es hat</em> perdent le <em>-b-</em> du radical.</p><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Pronom</th><th class="p-3 text-center font-semibold text-green-700">Forme</th><th class="p-3 text-left font-semibold text-gray-600">Exemple</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium">ich</td><td class="p-3 text-center font-bold text-green-700">habe</td><td class="p-3 text-gray-500 italic">Ich habe einen Hund. - J&#39;ai un chien.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">du</td><td class="p-3 text-center font-bold text-green-700">hast</td><td class="p-3 text-gray-500 italic">Du hast Hunger. - Tu as faim.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-medium">er/sie/es</td><td class="p-3 text-center font-bold text-green-700">hat</td><td class="p-3 text-gray-500 italic">Sie hat Zeit. - Elle a le temps.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">wir</td><td class="p-3 text-center font-bold text-green-700">haben</td><td class="p-3 text-gray-500 italic">Wir haben Gluck. - Nous avons de la chance.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-medium">ihr</td><td class="p-3 text-center font-bold text-green-700">habt</td><td class="p-3 text-gray-500 italic">Ihr habt Recht. - Vous avez raison.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">sie/Sie</td><td class="p-3 text-center font-bold text-green-700">haben</td><td class="p-3 text-gray-500 italic">Sie haben Kinder. - Ils ont des enfants.</td></tr></tbody></table></div><h2 id="werden-devenir-auxiliaire-du-futur" tabindex="-1">werden - devenir / auxiliaire du futur <a class="header-anchor" href="#werden-devenir-auxiliaire-du-futur" aria-label="Permalink to “werden - devenir / auxiliaire du futur”">​</a></h2><p><em>Werden</em> signifie &quot;devenir&quot; mais sert aussi a former le futur (module 4). Sa conjugaison est a connaître.</p><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Pronom</th><th class="p-3 text-center font-semibold text-green-700">Forme</th><th class="p-3 text-left font-semibold text-gray-600">Exemple</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium">ich</td><td class="p-3 text-center font-bold text-green-700">werde</td><td class="p-3 text-gray-500 italic">Ich werde Arzt. - Je deviens medecin.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">du</td><td class="p-3 text-center font-bold text-green-700">wirst</td><td class="p-3 text-gray-500 italic">Du wirst mude. - Tu deviens fatigue.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-medium">er/sie/es</td><td class="p-3 text-center font-bold text-green-700">wird</td><td class="p-3 text-gray-500 italic">Es wird kalt. - Il fait de plus en plus froid.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">wir</td><td class="p-3 text-center font-bold text-green-700">werden</td><td class="p-3 text-gray-500 italic">Wir werden alter. - Nous vieillissons.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-medium">ihr</td><td class="p-3 text-center font-bold text-green-700">werdet</td><td class="p-3 text-gray-500 italic">Ihr werdet sehen. - Vous verrez.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">sie/Sie</td><td class="p-3 text-center font-bold text-green-700">werden</td><td class="p-3 text-gray-500 italic">Sie werden kommen. - Ils viendront.</td></tr></tbody></table></div><h2 id="expressions-courantes-avec-sein-et-haben" tabindex="-1">Expressions courantes avec sein et haben <a class="header-anchor" href="#expressions-courantes-avec-sein-et-haben" aria-label="Permalink to “Expressions courantes avec sein et haben”">​</a></h2><p>Ces tournures s&#39;utilisent constamment, apprends-les telles quelles :</p><table tabindex="0"><thead><tr><th>Allemand</th><th>Français</th></tr></thead><tbody><tr><td><em>Ich habe Hunger.</em></td><td>J&#39;ai faim.</td></tr><tr><td><em>Ich habe Durst.</em></td><td>J&#39;ai soif.</td></tr><tr><td><em>Ich habe Angst.</em></td><td>J&#39;ai peur.</td></tr><tr><td><em>Ich bin mude.</em></td><td>Je suis fatigue(e).</td></tr><tr><td><em>Ich bin krank.</em></td><td>Je suis malade.</td></tr><tr><td><em>Ich bin satt.</em></td><td>Je n&#39;ai plus faim.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Hunger, Durst, Angst - pas de &quot;avoir&quot; en français</p><p>Faim, soif, peur se disent avec <em>haben</em> (avoir) en allemand. <em>Ich habe Hunger</em> signifie litteralement &quot;j&#39;ai faim&quot;. Même logique qu&#39;en français pour ces expressions.</p></div>',18)])])}const p=t(d,[["render",i]]);export{m as __pageData,p as default};
